import { useState, useEffect } from "react";
import { 
  FaWhatsapp, FaQrcode, FaSearch, FaTimes, FaHistory, 
  FaTruck, FaUser, FaPhoneAlt, FaFileInvoice, FaPrint, FaTrash 
} from "react-icons/fa";

// ── Configuration ────────────────────────────────────────────────────────────
const STATUSES = ["Picked Up", "Washing", "Ironing", "Ready", "Out for Delivery", "Delivered"];
const STORAGE_KEY = "dcl_master_store";

const C = {
  blue: "#0077b6", purple: "#7209b7", pink: "#f72585", dark: "#0a0f2e", green: "#10b981", red: "#ef4444"
};

// ── Helper: Print Slip ───────────────────────────────────────────────────────
const printTrackingSlip = (order) => {
  const url = `${window.location.origin}/track/${order.token}`;
  const qr = `https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=${encodeURIComponent(url)}`;
  const win = window.open("", "PRINT", "height=600,width=400");
  win.document.write(`
    <html><body style="font-family:monospace; text-align:center; padding:20px;">
      <h2>DEEP CITADEL</h2>
      <p>Order ID: ${order.id}</p>
      <div style="border-top:1px dashed #000; margin:10px 0;"></div>
      <p>Customer: ${order.customer}</p>
      <p><b>TRACKING TOKEN:</b></p>
      <h1 style="margin:5px 0;">${order.token}</h1>
      <img src="${qr}" style="margin:10px 0;"/>
      <p>Scan to track your laundry status</p>
      <div style="border-top:1px dashed #000; margin:10px 0;"></div>
      <p>Thank you for your business!</p>
    </body></html>
  `);
  win.document.close();
  win.print();
};

export default function DeepCitadelApp() {
  const [view, setView] = useState("pos"); 
  const [orders, setOrders] = useState(() => JSON.parse(localStorage.getItem(STORAGE_KEY) || "[]"));

  useEffect(() => { localStorage.setItem(STORAGE_KEY, JSON.stringify(orders)); }, [orders]);

  return (
    <div style={UI.mainWrapper}>
      <style>{`
        @keyframes mesh { 0% { background-position: 0% 50%; } 50% { background-position: 100% 50%; } 100% { background-position: 0% 50%; } }
        .glass { background: rgba(255, 255, 255, 0.92); backdrop-filter: blur(10px); border: 1px solid rgba(255, 255, 255, 0.3); border-radius: 20px; }
      `}</style>

      {/* Persistent Navigation - No Login Required */}
      <nav style={UI.nav}>
        <div style={{fontWeight:900, fontSize:"1.2rem"}}>DEEP CITADEL</div>
        <div style={{display:"flex", gap:"8px"}}>
          <button onClick={() => setView("pos")} style={view === "pos" ? UI.navBtnActive : UI.navBtn}><FaPlus/> POS</button>
          <button onClick={() => setView("staff")} style={view === "staff" ? UI.navBtnActive : UI.navBtn}><FaHistory/> Status</button>
          <button onClick={() => setView("track")} style={view === "track" ? UI.navBtnActive : UI.navBtn}><FaSearch/> Track</button>
        </div>
      </nav>

      <div style={{maxWidth: "1100px", margin: "0 auto", padding: "20px"}}>
        
        {/* VIEW 1: POS / ORDER CREATION */}
        {view === "pos" && (
          <div style={{display:"grid", gridTemplateColumns: window.innerWidth < 800 ? "1fr" : "1.2fr 1fr", gap: "20px"}}>
            <div className="glass" style={{padding:"25px"}}>
              <h3 style={{marginBottom:"20px"}}>Service Menu</h3>
              {["Wash & Fold", "Dry Cleaning", "Ironing Only", "Duvet/Large"].map(s => (
                <div key={s} style={UI.serviceRow}>
                  <span style={{fontWeight:700}}>{s}</span>
                  <button onClick={() => alert(`${s} added`)} style={UI.addBtn}><FaPlus/></button>
                </div>
              ))}
            </div>

            <div className="glass" style={{padding:"25px"}}>
              <h3>New Order</h3>
              <div style={UI.inputField}><FaUser color={C.blue}/><input id="custName" placeholder="Customer Name" style={UI.bareInput}/></div>
              <div style={UI.inputField}><FaPhoneAlt color={C.blue}/><input id="custPhone" placeholder="Phone Number" style={UI.bareInput}/></div>
              <button 
                style={UI.confirmBtn}
                onClick={() => {
                  const name = document.getElementById("custName").value;
                  if(!name) return alert("Enter name");
                  const token = Math.random().toString(36).substring(2, 8).toUpperCase();
                  const newOrder = {
                    token, id: "#"+Math.floor(1000+Math.random()*9000),
                    customer: name, status: "Picked Up",
                    date: new Date().toLocaleString(),
                    history: [{status: "Picked Up", time: new Date().toLocaleTimeString()}]
                  };
                  setOrders([newOrder, ...orders]);
                  printTrackingSlip(newOrder);
                }}
              >
                Complete & Print Slip
              </button>
            </div>
          </div>
        )}

        {/* VIEW 2: STAFF STATUS UPDATE */}
        {view === "staff" && (
          <div className="glass" style={{padding:"25px"}}>
            <h3>Live Order Management</h3>
            {orders.map(o => (
              <div key={o.token} style={UI.orderListRow}>
                <div style={{flex:1}}>
                  <div style={{fontWeight:800}}>{o.customer} <span style={{color:C.blue}}>{o.id}</span></div>
                  <div style={{fontSize:"11px", color:"#666"}}>Token: <b>{o.token}</b></div>
                </div>
                <select 
                  value={o.status} 
                  onChange={(e) => {
                    const updated = orders.map(item => item.token === o.token ? 
                      {...item, status: e.target.value, history: [...item.history, {status: e.target.value, time: new Date().toLocaleTimeString()}]} : item
                    );
                    setOrders(updated);
                  }}
                  style={UI.select}
                >
                  {STATUSES.map(s => <option key={s} value={s}>{s}</option>)}
                </select>
                <button onClick={() => setOrders(orders.filter(x => x.token !== o.token))} style={UI.deleteBtn}><FaTrash/></button>
              </div>
            ))}
          </div>
        )}

        {/* VIEW 3: CUSTOMER TRACKING */}
        {view === "track" && (
          <div style={{maxWidth:"500px", margin:"40px auto"}}>
            <div className="glass" style={{padding:"35px", textAlign:"center"}}>
              <FaTruck size={40} color={C.blue} style={{marginBottom:"15px"}}/>
              <h2>Track Laundry</h2>
              <input 
                id="trackInp" 
                placeholder="Enter 6-Digit Token" 
                style={{...UI.bareInput, border:`2px solid ${C.blue}`, borderRadius:"10px", padding:"15px", textAlign:"center", fontSize:"1.5rem", marginBottom:"15px"}}
              />
              <button 
                style={UI.confirmBtn}
                onClick={() => {
                  const val = document.getElementById("trackInp").value.toUpperCase();
                  const found = orders.find(x => x.token === val);
                  if(found) alert(`Status: ${found.status}`);
                  else alert("Token not found");
                }}
              >
                Search Status
              </button>
            </div>
          </div>
        )}

      </div>
    </div>
  );
}

